// utils/formDataMapper.js
import dayjs from "dayjs"

/**
 * Format date to ISO string
 * @param {*} dateValue - Date value (dayjs, Date, or string)
 * @returns {string|null} - ISO string or null
 */
export const formatDateToISO = dateValue => {
  if (!dateValue) return null

  // Nếu là dayjs object
  if (dayjs.isDayjs(dateValue)) {
    return dateValue.toISOString()
  }

  // Nếu là Date object
  if (dateValue instanceof Date) {
    return dateValue.toISOString()
  }

  // Nếu là string, parse thành dayjs rồi convert
  if (typeof dateValue === "string") {
    const parsed = dayjs(dateValue)
    return parsed.isValid() ? parsed.toISOString() : null
  }

  return null
}

/**
 * Map form values to API schema
 * @param {Object} formValues - Form values from Ant Design form
 * @param {Object} metadata - Additional metadata (images, package data)
 * @returns {Object} - Mapped data according to API schema
 */
const extractUUID = str => {
  const match = str.match(
    /[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}/,
  )
  return match ? match[0] : null
}

export const mapFormDataToAPISchema = (formValues, metadata) => {
  return {
    // Personal Information
    FullName: formValues.fullName || "",
    DateOfBirth: formatDateToISO(formValues.birthDate),
    Identification: formValues.cccdId || "",
    IdentificationIssueDate: formatDateToISO(formValues.issueDate),
    Occupation: formValues.Occupation || "",

    // Residence Address (Địa chỉ thường trú từ CCCD)
    ResidenceAddress: formValues.originalAddress || "",
    ResidenceWardID: parseInt(formValues.wardId) || 0,
    ResidenceDistrictID: parseInt(formValues.districtId) || 0,
    ResidenceProvinceID: parseInt(formValues.provinceId) || 0,

    // Contact Address (Địa chỉ liên hệ hiện tại)
    ContactAddress: formValues.ContactAddress || "",

    ContactWardID: parseInt(formValues.ContactWard) || 0,
    ContactDistrictID: parseInt(formValues.ContactDistrict) || 0,
    ContactProvinceID: parseInt(formValues.ContactProvince) || 0,

    // Gender mapping: "Nam" -> 1, "Nữ" -> 0, other -> 0
    Gender: formValues.gender === "Nam" ? 1 : 0,

    // Contact Information
    Email: formValues.Email || "",
    PhoneNumber: formValues.PhoneNumber || "",

    // Images
    Avatar: metadata.avatarImage || "",
    CCCDImage: metadata.cccdImage || "",

    // Default/System values
    Status: 0, // Default status - pending approval
    MemberID: null, // Will be generated by backend
    // Cuối hàm mapFormDataToAPISchema
    AccountID: extractUUID(formValues.AccountID) || null,
  }
}

/**
 * Validate required fields before submission
 * @param {Object} mappedData - Mapped data
 * @returns {Object} - { isValid, missingFields }
 */
export const validateRequiredFields = mappedData => {
  const requiredFields = [
    { key: "FullName", label: "Họ và tên" },
    { key: "DateOfBirth", label: "Ngày sinh" },
    { key: "Identification", label: "Số CCCD" },
    { key: "IdentificationIssueDate", label: "Ngày cấp CCCD" },
    // { key: "Email", label: "Email" },
    // { key: "PhoneNumber", label: "Số điện thoại" },
    // { key: "PackageID", label: "Gói hội viên" },
  ]

  const missingFields = requiredFields.filter(field => {
    const value = mappedData[field.key]
    return !value || value === "" || value === null || value === undefined
  })

  return {
    isValid: missingFields.length === 0,
    missingFields: missingFields.map(field => field.label),
  }
}
