import { Checkbox, Col, Row } from "antd"
import SvgIcon from "src/components/SvgIcon"
import './InformationApplication.scss'

const InformationApplication = ({ onChange, checkedValues, confirmError }) => {
  const checkboxItems = [
    {
      label:
        "Tôi xác nhận thông tin và Đồng ý với Điều khoản, Điều kiện và Chính sách Bảo mật.",
      errorMessage: "Vui lòng đồng ý với điều khoản và chính sách.",
    },
  ]

  const renderCheckbox = (item, index) => {
    const isChecked = checkedValues[index]
    const hasError = confirmError && !isChecked

    return (
      <div key={index} style={{ marginBottom: 12 }}>
        <Checkbox
          checked={isChecked}
          onChange={e => onChange(index, e.target.checked)}
        >
          <b className="fs-12">{item.label}</b>
        </Checkbox>
        {hasError && (
          <div style={{ color: "red", fontSize: 12, marginTop: 4 }}>
            {item.errorMessage}
          </div>
        )}
      </div>
    )
  }

  return (
    <div className="business-register__step-notice1 mt-14">
      <div className="notice-content">
        <Row>
          <Col span={13}>
            <div className="d-flex-start mb-10">
              <SvgIcon name="notice-success" />
              <div className="fw-600 mt-8 mb-8 ml-10">
                Thông tin xử lý ứng dụng
              </div>
            </div>
            <div className="fs-14 ml-20">
              <ul>
                <li>Tất cả thông tin được cung cấp sẽ được xác minh</li>
                <li>Thời gian xử lý thường 3-5 ngày làm việc</li>
                <li>Bạn sẽ nhận được email cập nhật trạng thái đơn</li>
                <li>Có thể yêu cầu thêm tài liệu nếu cần</li>
                <li>
                  Sau khi được chấp thuận, bạn sẽ nhận được quyền hội viên
                </li>
              </ul>
            </div>
          </Col>

          <Col span={11}>
            <div className="coinfirm-content">
              <div className="d-flex-start" style={{ gap: "10px" }}>
                <SvgIcon name="t_warning_default" />
                <div className="fw-600 mt-8 ml-10 fs-16">Xác nhận cuối cùng</div>
              </div>
              <div className="fs-14 mt-14">
                {checkboxItems.map(renderCheckbox)}
              </div>
            </div>
          </Col>
        </Row>
      </div>
    </div>
  )
}

export default InformationApplication
