import { UploadOutlined, UserOutlined, DeleteOutlined } from "@ant-design/icons"
import { Upload, message, Button } from "antd"
import { useState } from "react"
import '../styles/IndividualRegistration.scss'

const ImageUploadPreview = ({
  previewImage,
  setPreviewImage,
  fieldName,
  form,
  label = "Ảnh",
  onFileChange,
  disabled = false,
}) => {
  const [loading, setLoading] = useState(false)

  const beforeUpload = file => {
    const isJpgOrPng = file.type === "image/jpeg" || file.type === "image/png"
    if (!isJpgOrPng) {
      message.error("Chỉ chấp nhận file JPG/PNG!")
      return false
    }

    const isLt2M = file.size / 1024 / 1024 < 2
    if (!isLt2M) {
      message.error("Kích thước ảnh phải nhỏ hơn 2MB!")
      return false
    }

    // Create preview
    const reader = new FileReader()
    reader.onload = e => {
      setPreviewImage(e.target.result)
    }
    reader.readAsDataURL(file)

    // Update form field
    form.setFieldsValue({ [fieldName]: file })

    // Pass file to parent if callback provided
    if (onFileChange) {
      onFileChange(file)
    }

    return false // Prevent auto upload
  }

  // Handle delete image
  const handleDeleteImage = e => {
    e.stopPropagation() // Prevent triggering upload when clicking delete
    setPreviewImage(null)
    form.setFieldsValue({ [fieldName]: null })

    // Notify parent component about deletion
    if (onFileChange) {
      onFileChange(null)
    }

    message.success("Đã xóa ảnh thành công")
  }

  const uploadButton = (
    <div style={{ padding: "32px" }}>
      <UploadOutlined style={{ fontSize: "24px" }} className="method-icon" />
      <div style={{ marginTop: 8 }}>Tải lên</div>
    </div>
  )

  return (
    <div className="image-upload-preview">
      <Upload
        name={fieldName}
        listType="picture-card"
        className="avatar-uploader"
        showUploadList={false}
        beforeUpload={beforeUpload}
        disabled={disabled}
      >
        {previewImage ? (
          <div style={{ position: "relative", width: "100%", height: "100%" }}>
            <img
              alt="cccd"
              height={100}
              src={previewImage}
              style={{
                cursor: "pointer",
                width: "100%",
                height: "100%",
                objectFit: "cover",
              }}
            />
            {!disabled && (
              <Button
                type="text"
                danger
                size="small"
                icon={<DeleteOutlined />}
                onClick={handleDeleteImage}
                style={{
                  position: "absolute",
                  top: "4px",
                  right: "4px",
                  backgroundColor: "rgba(255, 255, 255, 0.8)",
                  border: "none",
                  borderRadius: "50%",
                  width: "24px",
                  height: "24px",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              />
            )}
          </div>
        ) : (
          uploadButton
        )}
      </Upload>
      <div className="upload-hint">
        <p style={{ fontSize: "13px", color: "#8c8c8c", marginTop: "16px" }}>
          Định dạng: JPG, PNG. Kích thước tối đa: 2MB
        </p>
      </div>
    </div>
  )
}

export default ImageUploadPreview
