import { CameraOutlined, UploadOutlined } from "@ant-design/icons"
import { Card, Col, Form, Input, message, Radio, Row, Tabs } from "antd"
import dayjs from "dayjs"
import customParseFormat from "dayjs/plugin/customParseFormat"
import { useEffect, useRef, useState } from "react"
import DatePickerCustom from "src/components/Date/DatePickerCustom"
import ButtonCustom from "src/components/MyButton/Button"
import ScanQR from "src/components/ScannerQr"
import GuestService from "src/services/GuestService"
import UserService from "src/services/UserService"
import ImageUploadPreview from "../../IndividualRegistration/components/ImageUploadPreview"
import "../styles/IndividualRegistration.scss"
import {
  parseDate,
  parseIDCardData,
  validateBirthDate,
  validateDate,
} from "../utils/cccdUtils"
import NoticeStep from "./NoticeStep"

dayjs.extend(customParseFormat)

const { TabPane } = Tabs

const Step1 = ({ form, next, metadata, updateMetadata }) => {
  const [scanQRVisible, setScanQRVisible] = useState(undefined)
  const [isUploading, setIsUploading] = useState(false)
  const [scanMethod, setScanMethod] = useState(null)
  const [previewCCCD, setPreviewCCCD] = useState(metadata.cccdImage)
  const [isConvertingAddress, setIsConvertingAddress] = useState(false)
  const [isMobile, setIsMobile] = useState(false)

  const selectAddressRef = useRef()

  useEffect(() => {
    if (metadata.cccdImage) {
      setPreviewCCCD(metadata.cccdImage)
    }
  }, [metadata.cccdImage])

  const fillFormWithCCCDData = parsedData => {
    const birthDate = parseDate(parsedData.birthDate)
    const issueDate = parseDate(parsedData.issueDate)

    form.setFieldsValue({
      cccdId: parsedData.id,
      fullName: parsedData.name,
      birthDate: birthDate,
      gender: parsedData.gender,
      issueDate: issueDate,
      originalAddress: parsedData.address,
    })
  }

  const resetFormData = () => {
    form.setFieldsValue({
      cccdId: "",
      fullName: "",
      birthDate: null,
      gender: "",
      issueDate: null,
      originalAddress: "",
    })
    setPreviewCCCD(null)
    updateMetadata({ cccdImage: null, isAutoFilled: false })
  }

  const handleScanResult = data => {
    try {
      if (data.raw) {
        const parsedData = parseIDCardData(data.raw)
        updateMetadata({ isAutoFilled: true })
        fillFormWithCCCDData(parsedData)
        message.success("Quét CCCD thành công!")
        setScanQRVisible(false)
      }
    } catch (error) {
      message.error("Có lỗi xảy ra khi xử lý dữ liệu CCCD")
    }
  }

  const handleUploadCCCD = async file => {
    if (!file) {
      try {
        setIsUploading(true)
        resetFormData()
        return true
      } catch (error) {
        message.error("Có lỗi xảy ra khi xóa ảnh CCCD")
        return false
      } finally {
        setIsUploading(false)
      }
    }

    setIsUploading(true)
    try {
      // Scan QR from image
      const scanResponse = await UserService.scanQRAccount(file)
      if (scanResponse?.data) {
        const parsedData = parseIDCardData(scanResponse.data)
        updateMetadata({ isAutoFilled: true })
        fillFormWithCCCDData(parsedData)
        message.success("Quét thông tin CCCD thành công!")
      }

      // Upload image
      const formData = new FormData()
      formData.append("file", file)
      const uploadResponse = await GuestService.uploadFile(formData)

      if (uploadResponse?.Object) {
        const imageUrl = uploadResponse.Object
        updateMetadata({ cccdImage: imageUrl })
        setPreviewCCCD(imageUrl)
      }

      return true
    } catch (error) {
      console.error("Error uploading file:", error)
      return false
    } finally {
      setIsUploading(false)
    }
  }

  const handleContinue = async () => {
    try {
      await form.validateFields([
        "cccdId",
        "fullName",
        "birthDate",
        "gender",
        "streetAddress",
        "CCCD",
      ])

      const addressData = selectAddressRef.current?.address || {}
      form.setFieldsValue({
        provinceName: addressData.province?.children,
        districtName: addressData.district?.children,
        wardName: addressData.ward?.children,
      })

      next()
    } catch (error) {
      message.error("Vui lòng điền đầy đủ thông tin bắt buộc")
    }
  }
  const uploadTab = (
    <TabPane
      tab={
        <span className="tab-label">
          <UploadOutlined className="method-icon" /> Upload ảnh
        </span>
      }
      key="upload"
    >
      <div className="scan-methods">
        <Card
          hoverable
          className={`method-card ${scanMethod === "upload" ? "selected" : ""}`}
          style={{ border: "2px dashed #009688" }}
        >
          <div className="p-1 method-content text-center">
            <Form.Item
              name="CCCD"
              rules={[
                { required: true, message: "Vui lòng tải ảnh CCCD của bạn" },
              ]}
            >
              <ImageUploadPreview
                previewImage={previewCCCD}
                setPreviewImage={setPreviewCCCD}
                fieldName="CCCD"
                form={form}
                label=""
                onFileChange={handleUploadCCCD}
                disabled={isUploading}
              />
            </Form.Item>
          </div>
        </Card>
      </div>
    </TabPane>
  )

  const cameraTab = (
    <TabPane
      tab={
        <span className="tab-label">
          <CameraOutlined className="method-icon" /> Quét QR
        </span>
      }
      key="camera"
    >
      <div className="scan-methods">
        <Card
          hoverable
          className={`p-1 method-card ${
            scanMethod === "camera" ? "selected" : ""
          }`}
          style={{ border: "2px dashed #009688" }}
          onClick={() => {
            setScanMethod("camera")
            setScanQRVisible(true)
          }}
        >
          <div className="method-content text-center">
            <CameraOutlined
              style={{ fontSize: "54px" }}
              className="method-icon mr-8 mb-16"
            />
            <div className="mb-16">
              Sử dụng camera để quét mã QR thẻ CCCD hoặc VNeID
            </div>
            <div>
              <ButtonCustom>Mở camera</ButtonCustom>
            </div>
          </div>
        </Card>
      </div>
    </TabPane>
  )

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768)
    }
    handleResize()
    window.addEventListener("resize", handleResize)
    return () => window.removeEventListener("resize", handleResize)
  }, [])

  return (
    <div className="business-register__step">
      <Form
        form={form}
        layout="vertical"
        className="registration-form"
        preserve={true}
      >
        <NoticeStep
          description="Bạn có thể quét CCCD để hệ thống tự động điền thông tin của bạn vào các mục thông tin cá nhân."
          icon="scan-qr"
        />

        <Row gutter={24} className="cccd-scan-step">
          <Col span={11}>
            <div className="box-infor1">
              <h3 className="fw-600">Quét CCCD</h3>

              <Tabs
                className="payment-tabs"
                key={isMobile ? "mobile" : "desktop"}
              >
                {isMobile ? (
                  <>
                    {cameraTab}
                    {uploadTab}
                  </>
                ) : (
                  <>
                    {uploadTab}
                    {cameraTab}
                  </>
                )}
              </Tabs>
            </div>
          </Col>

          <Col span={13}>
            <div className="box-infor1">
              <h3 className="fw-600">
                Thông tin cá nhân
                {metadata.isAutoFilled && (
                  <span
                    style={{
                      color: "#52c41a",
                      fontSize: "14px",
                      fontWeight: "normal",
                      marginLeft: "8px",
                    }}
                  >
                    (Đã tự động điền từ CCCD)
                  </span>
                )}
              </h3>

              <Row gutter={16}>
                <Col span={12}>
                  <Form.Item
                    name="cccdId"
                    label="Số CCCD"
                    rules={[
                      { required: true, message: "Vui lòng nhập số CCCD" },
                      {
                        pattern: /^\d{12}$/,
                        message: "Số CCCD phải có 12 chữ số",
                      },
                    ]}
                  >
                    <Input placeholder="Nhập số CCCD" maxLength={12} />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="fullName"
                    label="Họ và tên"
                    rules={[
                      { required: true, message: "Vui lòng nhập họ và tên" },
                      { min: 2, message: "Họ tên phải có ít nhất 2 ký tự" },
                    ]}
                  >
                    <Input placeholder="Nhập họ và tên" />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="birthDate"
                    label="Ngày sinh"
                    rules={[{ required: true, validator: validateBirthDate }]}
                  >
                    <DatePickerCustom
                      placeholder="Chọn ngày sinh"
                      format="DD/MM/YYYY"
                      disabledDate={current =>
                        current && current.isAfter(dayjs().endOf("day"))
                      }
                    />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="gender"
                    label="Giới tính"
                    rules={[
                      { required: true, message: "Vui lòng chọn giới tính" },
                    ]}
                  >
                    <Radio.Group>
                      <Radio value="Nam">Nam</Radio>
                      <Radio value="Nữ">Nữ</Radio>
                    </Radio.Group>
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="issueDate"
                    label="Ngày cấp CCCD"
                    rules={[{ required: true, validator: validateDate }]}
                  >
                    <DatePickerCustom
                      placeholder="Chọn ngày cấp"
                      format="DD/MM/YYYY"
                      disabledDate={current =>
                        current &&
                        (current.isAfter(dayjs().endOf("day")) ||
                          current.isBefore(dayjs("2016-01-01")))
                      }
                    />
                  </Form.Item>
                </Col>
                <Col span={16}>
                  <Form.Item
                    name="originalAddress"
                    label="Địa chỉ thường trú"
                    rules={[{ required: true }]}
                  >
                    <Input placeholder="Địa chỉ thường trú" />
                  </Form.Item>
                </Col>
              </Row>
            </div>
          </Col>
        </Row>
        <div className="d-flex-end mr-10">
          <ButtonCustom
            type="primary"
            onClick={handleContinue}
            disabled={isConvertingAddress}
            loading={isUploading}
          >
            Tiếp tục
          </ButtonCustom>
        </div>
        {scanQRVisible !== undefined && (
          <ScanQR
            open={scanQRVisible}
            onCancel={() => setScanQRVisible(false)}
            onOk={handleScanResult}
          />
        )}
      </Form>
    </div>
  )
}

export default Step1
