import { Col, Form, Input, message, Row, Spin } from "antd"
import { useEffect, useState } from "react"
import ButtonCustom from "src/components/MyButton/Button"
import ImageUploadPreview from "../components/ImageUploadPreview"
import NoticeStep from "./NoticeStep"
import { getRegexMobile } from "src/lib/stringsUtils"
import GuestService from "src/services/GuestService"

const Step2 = ({ form, next, prev, metadata, updateMetadata }) => {
  const [previewAvatar, setPreviewAvatar] = useState(metadata.avatarImage)
  const [isUploadingAvatar, setIsUploadingAvatar] = useState(false)

  // ✅ Khôi phục dữ liệu avatar từ metadata
  useEffect(() => {
    if (metadata.avatarImage) {
      setPreviewAvatar(metadata.avatarImage)
    }
  }, [metadata.avatarImage])

  // ✅ Upload avatar
  const uploadAvatar = async file => {
    const localPreviewUrl = URL.createObjectURL(file)
    setPreviewAvatar(localPreviewUrl)
    setIsUploadingAvatar(true)

    try {
      const formData = new FormData()
      formData.append("file", file)
      const res = await GuestService.uploadFile(formData)
      const avatarUrl = res.Object

      updateMetadata({ avatarImage: avatarUrl })
      setPreviewAvatar(avatarUrl)
      URL.revokeObjectURL(localPreviewUrl)

      form.setFieldsValue({ Avatar: avatarUrl })
      message.success("Upload ảnh đại diện thành công!")
    } catch (error) {
      URL.revokeObjectURL(localPreviewUrl)
      setPreviewAvatar(metadata.avatarImage || null)
    } finally {
      setIsUploadingAvatar(false)
    }
  }

  const handleAvatarFileChange = async file => {
    if (file) await uploadAvatar(file)
  }

  const handleContinue = async () => {
    try {
      await form.validateFields([
        "FullName",
        "Identification",
        "Email",
        "PhoneNumber",
        "Occupation",
        "ContactStreetAddress",
        "ContactAddress",
        "Avatar",
      ])
      next()
    } catch (error) {
      message.error("Vui lòng kiểm tra lại thông tin đã nhập")
    }
  }

  return (
    <div className="business-register__step personal-info-step">
      <Form
        form={form}
        layout="vertical"
        className="registration-form"
        preserve={true}
      >
        <div className="business-register__step-notice">
          <NoticeStep
            description="Vui lòng bổ sung thông tin cá nhân của bạn."
            icon="user-info"
          />
        </div>

        <Row gutter={[16,16]} className="personal-info-step">
          {/* Cột ảnh đại diện */}
          <Col span={10}>
            <div className="box-infor">
              <h3 className="fw-600">Ảnh đại diện</h3>
              <Form.Item
                name="Avatar"
                rules={[
                  { required: true, message: "Vui lòng upload ảnh đại diện" },
                ]}
                className="upload-img"
              >
                <Spin spinning={isUploadingAvatar} tip="Đang upload ảnh...">
                  <ImageUploadPreview
                    previewImage={previewAvatar}
                    setPreviewImage={setPreviewAvatar}
                    fieldName="Avatar"
                    form={form}
                    label="Ảnh đại diện"
                    onFileChange={handleAvatarFileChange}
                    disabled={isUploadingAvatar}
                    loading={isUploadingAvatar}
                  />
                </Spin>
              </Form.Item>
            </div>
          </Col>

          {/* Cột thông tin liên hệ */}
          <Col span={14}>
            <div className="box-infor">
              <h3 className="fw-600">Thông tin liên hệ</h3>
              <Row gutter={[16, 16]} className="contact-info-form">
                <Col xs={24} span={12}>
                  <Form.Item
                    name="Occupation"
                    label="Nghề nghiệp"
                    rules={[
                      { required: true, message: "Vui lòng nhập nghề nghiệp" },
                    ]}
                  >
                    <Input placeholder="Nhập nghề nghiệp của bạn" />
                  </Form.Item>
                </Col>

                <Col xs={24} span={12}>
                  <Form.Item
                    name="PhoneNumber"
                    label="Số điện thoại"
                    rules={[
                      {
                        required: true,
                        message: "Vui lòng nhập số điện thoại",
                      },
                      {
                        pattern: getRegexMobile(),
                        message: "Số điện thoại không hợp lệ",
                      },
                    ]}
                  >
                    <Input placeholder="0123456789" />
                  </Form.Item>
                </Col>

                <Col xs={24} span={12}>
                  <Form.Item
                    name="Email"
                    label="Email"
                    rules={[
                      { required: true, message: "Vui lòng nhập email" },
                      { type: "email", message: "Email không hợp lệ" },
                    ]}
                  >
                    <Input placeholder="example@email.com" />
                  </Form.Item>
                </Col>

                <Col span={24}>
                  <Form.Item
                    name="ContactAddress"
                    label="Địa chỉ liên hệ"
                    rules={[
                      {
                        required: true,
                        message: "Vui lòng nhập địa chỉ chi tiết",
                      },
                    ]}
                  >
                    <Input placeholder="Số nhà, tên đường, thôn, xóm..." />
                  </Form.Item>
                </Col>
              </Row>
            </div>
          </Col>
        </Row>
      </Form>

      {/* Actions */}
      <div className="step-actions mt-15">
        <ButtonCustom
          type="default"
          style={{
            margin: "0 8px",
            backgroundColor: "#fff",
            color: "#01b39e",
            border: "1px solid #01b39e",
          }}
          onClick={prev}
        >
          Quay lại
        </ButtonCustom>
        <ButtonCustom
          type="primary"
          onClick={handleContinue}
          disabled={isUploadingAvatar}
        >
          Tiếp tục
        </ButtonCustom>
      </div>
    </div>
  )
}

export default Step2
