import { Form } from "antd"
import { useState, useCallback } from "react"
import { useNavigate } from "react-router-dom"
import LayoutCommon from "src/components/Common/LayoutCommon"
import notice from "src/components/Notice"
import StepsCustom from "src/components/StepsCustom"
import SvgIcon from "src/components/SvgIcon"
import ROUTER from "src/router/ROUTER"
import Step1 from "./components/Step1"
import Step2 from "./components/Step2"
import Step2_2 from "./components/Step2_2"
import Step3 from "./components/Step3"
import "./styles/IndividualRegistration.scss"
import GuestService from "src/services/GuestService"
import {
  mapFormDataToAPISchema,
  validateRequiredFields,
} from "./utils/formDataMapper"

const IndividualRegistration = () => {
  const nav = useNavigate()
  const [current, setCurrent] = useState(0)
  const [loading, setLoading] = useState(false)

  const [mainForm] = Form.useForm()

  const [formMetadata, setFormMetadata] = useState({
    cccdImage: null,
    avatarImage: null,
    isAutoFilled: false,
    treeExternalData: {},
  })

  const updateMetadata = useCallback(updates => {
    setFormMetadata(prev => ({ ...prev, ...updates }))
  }, [])

  const next = useCallback(() => {
    setCurrent(prev => prev + 1)
  }, [])

  const prev = useCallback(() => {
    setCurrent(prev => (prev > 0 ? prev - 1 : 0))
  }, [])

  const handleSubmit = async () => {
    try {
      setLoading(true)
      const formValues = await mainForm.validateFields()

      const mappedData = mapFormDataToAPISchema(formValues, formMetadata)

      const validation = validateRequiredFields(mappedData)
      if (!validation.isValid) return

      const res = await GuestService.RegisterIndividual(mappedData)
      if (res?.isError) return

      notice({
        msg: "Đăng ký thành công. Vui lòng chờ xác thực từ quản trị viên.",
        type: "success",
      })
      nav(ROUTER.HOME)
    } catch (err) {
      console.error(err)
    } finally {
      setLoading(false)
    }
  }

  const steps = [
    {
      title: (
        <div className="title-step">
          <div className="title-step__main">
            <b>Quét CCCD</b>
          </div>
          <div className="title-step__sub">Quét CCCD và xác thực thông tin</div>
        </div>
      ),
      icon: (
        <div className="icon-step">
          <SvgIcon name="cccd_1" />
        </div>
      ),
      content: (
        <Step1
          form={mainForm}
          next={next}
          metadata={formMetadata}
          updateMetadata={updateMetadata}
        />
      ),
    },
    {
      title: (
        <div className="title-step">
          <div className="title-step__main no-wrap">
            <b>Thông tin cá nhân</b>
          </div>
          <div className="title-step__sub">
            Bổ sung thông tin cá nhân và liên hệ
          </div>
        </div>
      ),
      icon: (
        <div className="icon-step">
          <SvgIcon name="diem-danh" />
        </div>
      ),
      content: (
        <Step2
          form={mainForm}
          next={next}
          prev={prev}
          metadata={formMetadata}
          updateMetadata={updateMetadata}
        />
      ),
    },
    {
      title: (
        <div className="title-step">
          <div className="title-step__main no-wrap">
            <b>Chọn đơn vị</b>
          </div>
          <div className="title-step__sub">
            Chọn đơn vị công tác hoặc tham gia
          </div>
        </div>
      ),
      icon: (
        <div className="icon-step">
          <SvgIcon name="building" />
        </div>
      ),
      content: (
        <Step2_2
          form={mainForm}
          next={next}
          prev={prev}
          metadata={formMetadata}
          updateMetadata={updateMetadata}
        />
      ),
    },
    {
      title: (
        <div className="title-step">
          <div className="title-step__main no-wrap">
            <b>Xác nhận lại</b>
          </div>
          <div className="title-step__sub">
            Xác nhận thông tin và chọn gói hội viên
          </div>
        </div>
      ),
      icon: (
        <div className="icon-step">
          <SvgIcon name="check-special" />
        </div>
      ),
      content: (
        <Step3
          form={mainForm}
          prev={prev}
          onSubmit={handleSubmit}
          setCurrent={setCurrent}
          metadata={formMetadata}
          updateMetadata={updateMetadata}
          loading={loading}
        />
      ),
    },
  ]

  const items = steps.map((item, index) => ({
    key: `step-${index}`,
    title: item.title,
    icon: item.icon,
  }))

  return (
    <div className="business-register">
      <LayoutCommon>
        <div className="business-register__title">
          <h2 className="business-register__title-main">
            Đăng Ký Hội Viên Cá Nhân
          </h2>
          <div className="business-register__title-sub">
            Hoàn tất đăng ký hội viên của bạn trong 4 bước đơn giản
          </div>
        </div>
        <div className="business-register__steps-box">
          <div className="mb-16">
            <StepsCustom
              labelPlacement="vertical"
              current={current}
              items={items}
            />
          </div>

          {steps?.map((item, idx) => (
            <div
              key={idx}
              style={{
                display: current === idx ? "block" : "none",
              }}
            >
              {item.content}
            </div>
          ))}
        </div>
      </LayoutCommon>
    </div>
  )
}

export default IndividualRegistration
