import SvgIcon from "src/components/SvgIcon"
import '../styles/IndividualRegistration.scss'

const NoticeStep = ({
  // title = "Thông Tin Doanh Nghiệp",
  description = `Nhập thông tin doanh nghiệp của bạn bên dưới. Bạn có thể sử dụng
            chức năng tra cứu Mã số thuế để tự động điền vào hầu hết các trường.`,
  icon = "building",
}) => {
  return (
    <div className="business-register__step-notice">
      <div className="notice-content  d-flex-start">
        <div>
          <SvgIcon name={icon} />
        </div>
        <div>
          <div className="">{description}</div>
        </div>
      </div>
    </div>
  )
}

export default NoticeStep
