import { Col, Form, Input, message, Row } from "antd"
import ButtonCustom from "src/components/MyButton/Button"
import UnitSelect from "./UnitSelect"

const Step2_2 = ({ form, next, prev, metadata, updateMetadata }) => {
  const handleUnitChange = node => {
    // Lưu cả ID và Tên đơn vị vào metadata
    updateMetadata({
      selectedUnit: {
        AccountID: node?.key || null,
        AccountName: node?.title || "", // ✅ thêm tên
      },
    })

    // Gán vào Form cha
    form.setFieldsValue({
      AccountID: node?.key || null,
      AccountName: node?.title || "",
    })
  }

  const handleNext = async () => {
    try {
      const values = await form.validateFields(["AccountID"])
      if (!values.AccountID) {
        message.error("Vui lòng chọn đơn vị trước khi tiếp tục")
        return
      }
      next()
    } catch (err) {
      message.error("Vui lòng chọn đơn vị trước khi tiếp tục")
    }
  }

  return (
    <div style={{ display: "flex" }}>
      <div
        style={{
          width: window.matchMedia("(max-width: 768px)").matches
            ? "100%"
            : "1300px",
        }}
      >
        <Form form={form} layout="vertical" preserve={true}>
          {/* Hidden field lưu AccountID */}
          <Form.Item
            name="AccountID"
            hidden
            rules={[{ required: true, message: "Vui lòng chọn đơn vị" }]}
          >
            <Input />
          </Form.Item>

          <Form.Item name="AccountName" hidden>
            <Input />
          </Form.Item>

          <Row justify="center">
            <Col xs={24}>
              <div>
                <UnitSelect onChange={handleUnitChange} />
              </div>
            </Col>
          </Row>

          <div className="step-actions mt-15">
            <ButtonCustom
              type="default"
              onClick={prev}
              style={{
                margin: "0 8px",
                backgroundColor: "#fff",
                color: "#01b39e",
                border: "1px solid #01b39e",
              }}
            >
              Quay lại
            </ButtonCustom>
            <ButtonCustom type="primary" onClick={handleNext}>
              Tiếp tục
            </ButtonCustom>
          </div>
        </Form>
      </div>
    </div>
  )
}

export default Step2_2
